/**
 * List donations for a specific project.
 *
 * @route GET /api/donations/project/:projectId
 * @param {import('express').Request} req - Express request containing the project id and pagination options.
 * @param {import('express').Response} res - Express response object.
 * @param {import('express').NextFunction} next - Express error middleware.
 * @returns {Promise<void>} Sends the paginated donation history.
 * @throws {Error} If the donation query fails.
 */
router.get("/project/:projectId", async (req, res, next) => {
  try {
    const limit = Math.min(parseInt(req.query.limit, 10) || 20, 100);
    const hasCursor = Boolean(req.query.cursor);
    const values = hasCursor
      ? [req.params.projectId, req.query.cursor, limit + 1]
      : [req.params.projectId, limit + 1];

    const query = hasCursor
      ? `SELECT * FROM donations
         WHERE project_id = $1
           AND created_at < $2::timestamptz
         ORDER BY created_at DESC
         LIMIT $3`
      : `SELECT * FROM donations
         WHERE project_id = $1
         ORDER BY created_at DESC
         LIMIT $2`;

    const donations = (await pool.query(query, values)).rows.map(
      mapDonationRow,
    );
    const hasMore = donations.length > limit;
    const result = hasMore ? donations.slice(0, limit) : donations;
    const nextCursor = hasMore ? result[result.length - 1].createdAt : null;

    res.json({ success: true, data: result, nextCursor });
  } catch (e) {
    next(e);
  }
});

/**
 * List donations for a specific donor.
 *
 * @route GET /api/donations/donor/:publicKey
 * @param {import('express').Request} req - Express request containing the donor public key.
 * @param {import('express').Response} res - Express response object.
 * @param {import('express').NextFunction} next - Express error middleware.
 * @returns {Promise<void>} Sends the donor donation history.
 * @throws {Error} If validation or the donation query fails.
 */
router.get(
  "/donor/:publicKey",
  validate(z.object({ publicKey: stellarAddress }), "params"),
  async (req, res, next) => {
    try {
      const result = await pool.query(
        `SELECT * FROM donations
       WHERE donor_address = $1
       ORDER BY created_at DESC`,
        [req.params.publicKey],
      );
      res.json({ success: true, data: result.rows.map(mapDonationRow) });
    } catch (e) {
      next(e);
    }
  });

// GET /api/donations/:id - single donation fetch endpoint
router.get("/:id", async (req, res, next) => {
  try {
    const { id } = req.params;
    // Basic UUID validation
    if (
      !/^[0-9a-f]{8}-[0-9a-f]{4}-[1-5][0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$/i.test(
        id,
      )
    ) {
      throw new AppError("VALIDATION_ERROR", {
        field: "id",
        detail: "Invalid donation ID",
      });
    }

    const USDC_TO_XLM_RATE = parseFloat(process.env.USDC_TO_XLM_RATE || "8.0");
    const query = `
      SELECT 
        d.*,
        p.name AS project_name,
        pr.display_name AS donor_display_name,
        CASE
          WHEN d.currency = 'USDC' AND p.raised_xlm > 0
            THEN (d.amount * ${USDC_TO_XLM_RATE} * (p.co2_offset_kg::numeric / p.raised_xlm))
          WHEN d.currency = 'XLM' AND p.raised_xlm > 0
            THEN (d.amount_xlm * (p.co2_offset_kg::numeric / p.raised_xlm))
          ELSE 0
        END AS co2_offset_kg
      FROM donations d
      JOIN projects p ON d.project_id = p.id
      LEFT JOIN profiles pr ON d.donor_address = pr.public_key
      WHERE d.id = $1
    `;
    const result = await pool.query(query, [id]);

    if (!result.rows[0]) {
      throw new AppError("DONATION_NOT_FOUND");
    }
    const row = result.rows[0];
    const donationData = mapDonationRow(row);
    donationData.projectName = row.project_name;
    donationData.donorDisplayName = row.donor_display_name || null;
    donationData.co2OffsetKg = Math.round(
      Number.parseFloat(row.co2_offset_kg || "0"),
    );

    res.json({ success: true, data: donationData });
  } catch (e) {
    next(e);
  }
});

module.exports = router;
module.exports.recordDonation = recordDonation;

/**
 * src/routes/impact.js
 * Impact aggregation endpoints.
 *
 * - GET /api/impact/project/:id
 * - GET /api/impact/global
 * - GET /api/impact/donor/:publicKey
 *
 * All endpoints are cached for 5 minutes (process-local).
 */
"use strict";

const express = require("express");
const router = express.Router();
const pool = require("../db/pool");
const cache = require("../services/cache");
const redis = require("../services/redis");
const { AppError } = require("../errors");

const CACHE_TTL_MS = 5 * 60 * 1000;
const KG_CO2_PER_TREE = 21.77; // heuristic, used for treesEquivalent

function validateKey(k) {
  if (!k || !/^G[A-Z0-9]{55}$/.test(k)) {
    throw new AppError("INVALID_ADDRESS");
  }
}

function treesEquivalentFromKg(kg) {
  if (!Number.isFinite(kg) || kg <= 0) return 0;
  return Number((kg / KG_CO2_PER_TREE).toFixed(2));
}

function cacheKey(req) {
  return req.originalUrl;
}

function sendCached(req, res, payload) {
  cache.set(cacheKey(req), payload, CACHE_TTL_MS);
  res.set("Cache-Control", "public, max-age=300");
  return res.json(payload);
}

// GET /api/impact/project/:id
router.get("/project/:id", async (req, res, next) => {
  try {
    const hit = cache.get(cacheKey(req));
    if (hit) return res.json(hit);

    const projectResult = await pool.query(
      `SELECT id, category, raised_xlm, co2_offset_kg
       FROM projects
       WHERE id = $1`,
      [req.params.id],
    );
    if (!projectResult.rows[0]) throw new AppError("PROJECT_NOT_FOUND");

    const aggResult = await pool.query(
      `SELECT
        COALESCE(SUM(d.amount_xlm), 0) AS "totalDonationsXLM",
        COUNT(DISTINCT d.donor_address)::int AS "donorCount"
       FROM donations d
       WHERE d.project_id = $1
         AND (d.currency = 'XLM' OR d.currency IS NULL)`,
      [req.params.id],
    );

    const p = projectResult.rows[0];
    const totalDonationsXLM = Number.parseFloat(
      aggResult.rows[0].totalDonationsXLM || "0",
    );
    const donorCount = aggResult.rows[0].donorCount || 0;

    const raisedXlm = Number.parseFloat(p.raised_xlm?.toString() || "0");
    const projectCo2OffsetKg = Number.parseFloat(
      p.co2_offset_kg?.toString() || "0",
    );
    const kgPerXlm = raisedXlm > 0 ? projectCo2OffsetKg / raisedXlm : 0;
    const co2OffsetKg = Math.round(totalDonationsXLM * kgPerXlm);

    return sendCached(req, res, {
      success: true,
      data: {
        totalDonationsXLM: totalDonationsXLM.toFixed(7),
        donorCount,
        co2OffsetKg,
        treesEquivalent: treesEquivalentFromKg(co2OffsetKg),
        uniqueCountries: 0,
      },
    });
  } catch (e) {
    next(e);
  }
});

// GET /api/impact/global
router.get("/global", async (req, res, next) => {
  try {
    const cacheKey = "impact:global";
    const cached = await redis.get(cacheKey);
    if (cached) return res.json(cached);

    const result = await pool.query(`
      SELECT total_donated_xlm, total_co2_kg, total_trees,
             total_donations, total_projects, total_donors
      FROM global_impact
      WHERE id = 1`
    );
    const row = result.rows[0] || {};
    const totalDonatedXLM = Number.parseFloat(row.total_donated_xlm || "0");
    const co2OffsetKg = Math.round(Number.parseFloat(row.total_co2_kg || "0"));
    const totalTrees = Math.round(Number.parseFloat(row.total_trees || "0"));
    const payload = {
      success: true,
      data: {
        totalDonatedXLM: totalDonatedXLM.toFixed(7),
        donorCount: row.total_donors || 0,
        co2OffsetKg,
        treesEquivalent: treesEquivalentFromKg(co2OffsetKg),
        uniqueCountries: 0,
        totalDonations: row.total_donations || 0,
        totalProjects: row.total_projects || 0,
        totalDonors: row.total_donors || 0,
        totalTrees,
      },
    };
    await redis.set(cacheKey, payload, 300);
    return res.json(payload);
  } catch (e) {
    next(e);
  }
});

// GET /api/impact/donor/:publicKey
router.get("/donor/:publicKey", async (req, res, next) => {
  try {
    validateKey(req.params.publicKey);
