/**
 * Category breakdown — donations by project category.
 * @param {{ from?: Date|string, to?: Date|string }} [range]
 * @returns {Promise<Array>}
 */
async function getCategoryBreakdown(range = {}) {
  const { where, values } = dateClause(range.from, range.to, "d.created_at");
  const whereClause = where ? `${where} AND p.status = 'active'` : "WHERE p.status = 'active'";

  const result = await pool.query(
    `SELECT p.category,
            COUNT(DISTINCT d.id)::int AS "donationCount",
            COALESCE(SUM(d.amount_xlm), 0) AS "totalXLM",
            COUNT(DISTINCT d.donor_address)::int AS "donorCount"
     FROM donations d
     JOIN projects p ON p.id = d.project_id
     ${whereClause}
     GROUP BY p.category
     ORDER BY "totalXLM" DESC`,
    values,
  );

  return result.rows.map((r) => ({
    category: r.category,
    donationCount: r.donationCount,
    totalXLM: String(r.totalXLM || "0"),
    donorCount: r.donorCount,
  }));
}

/**
 * Platform growth metrics — cumulative and monthly totals.
 * @returns {Promise<object>}
 */
async function getPlatformGrowth() {
  const [summary, monthly] = await Promise.all([
    pool.query(
      `SELECT
         (SELECT COUNT(*)::int FROM projects) AS "totalProjects",
         (SELECT COUNT(*)::int FROM donations) AS "totalDonations",
         (SELECT COUNT(DISTINCT donor_address)::int FROM donations) AS "totalDonors",
         (SELECT COALESCE(SUM(amount_xlm), 0) FROM donations) AS "totalXLM",
         (SELECT COUNT(DISTINCT donor_address)::int
          FROM donations
          WHERE created_at >= NOW() - INTERVAL '30 days') AS "activeDonors30d",
         (SELECT COALESCE(SUM(amount_xlm), 0)
          FROM donations
          WHERE created_at >= NOW() - INTERVAL '30 days') AS "totalXLM30d"
       FROM (VALUES (1)) t`,
    ),
    pool.query(
      `SELECT
         DATE_TRUNC('month', created_at)::date AS "month",
         COUNT(*)::int AS "donations",
         COALESCE(SUM(amount_xlm), 0) AS "totalXLM",
         COUNT(DISTINCT donor_address)::int AS "donors"
       FROM donations
       GROUP BY DATE_TRUNC('month', created_at)
       ORDER BY "month" ASC`,
    ),
  ]);

  const s = summary.rows[0];
  return {
    summary: {
      totalProjects: Number(s.totalProjects),
      totalDonations: Number(s.totalDonations),
      totalDonors: Number(s.totalDonors),
      totalXLM: String(s.totalXLM || "0"),
      activeDonors30d: Number(s.activeDonors30d),
      totalXLM30d: String(s.totalXLM30d || "0"),
    },
    monthlyGrowth: monthly.rows.map((r) => ({
      month: r.month instanceof Date ? r.month.toISOString().slice(0, 7) : String(r.month).slice(0, 7),
      donations: Number(r.donations),
      totalXLM: String(r.totalXLM || "0"),
      donors: Number(r.donors),
    })),
  };
}

module.exports = {
  getDonationTrends,
  getProjectPerformance,
  getGeographicImpact,
  getDonorRetention,
  getCategoryBreakdown,
  getPlatformGrowth,
};

/**
 * src/services/circuitBreaker.js
 *
 * Reusable circuit breaker utility for the Stellar IndigoPay backend.
 *
 * States
 * ------
 *  CLOSED    – Normal operation. All calls pass through.
 *  OPEN      – Too many consecutive failures. Calls are rejected immediately
 *              without invoking the underlying function, giving the downstream
 *              time to recover.
 *  HALF_OPEN – The reset timeout has elapsed. The next call is attempted; on
 *              success the breaker transitions back to CLOSED; on failure it
 *              goes back to OPEN and resets the last-failure timer.
 *
 * Prometheus
 * ----------
 * Exports a `circuitBreakerGauge` Gauge keyed by `name` that encodes the
 * current state as an integer:
 *   0 = closed  (healthy)
 *   1 = half_open
 *   2 = open    (circuit tripped)
 *
 * Usage
 * -----
 *   const { CircuitBreaker } = require('./circuitBreaker');
 *   const breaker = new CircuitBreaker({ name: 'soroban_rpc', failureThreshold: 5, resetTimeout: 30_000 });
 *   const result = await breaker.call(() => rpcServer.sendTransaction(xdr));
 */
"use strict";

const logger = require("../logger");
const { Gauge } = require("prom-client");
const { registry } = require("./metrics");

/** @enum {string} */
const STATES = Object.freeze({
  CLOSED: "closed",
  OPEN: "open",
  HALF_OPEN: "half_open",
});

/** Numeric encoding for the Prometheus gauge. */
const STATE_VALUES = {
  [STATES.CLOSED]: 0,
  [STATES.HALF_OPEN]: 1,
  [STATES.OPEN]: 2,
};

/**
 * Prometheus gauge tracking circuit breaker state per named breaker.
 * Registered on the shared registry so it appears at /metrics automatically.
 */
const circuitBreakerGauge = new Gauge({
  name: "indigopay_soroban_circuit_breaker_state",
  help: "Circuit breaker state: 0=closed (healthy), 1=half_open, 2=open (tripped)",
  labelNames: ["name"],
  registers: [registry],
});

class CircuitBreaker {
  /**
   * @param {object} opts
   * @param {string}  [opts.name='default']          Label shown in Prometheus and logs.
   * @param {number}  [opts.failureThreshold=5]      Consecutive failures before opening.
   * @param {number}  [opts.resetTimeout=30_000]     Ms to wait before attempting half-open.
   */
  constructor(opts = {}) {
    this.name = opts.name || "default";
    this.failureThreshold = opts.failureThreshold || 5;
    this.resetTimeout = opts.resetTimeout || 30_000;

    this.state = STATES.CLOSED;
    this.failureCount = 0;
    this.lastFailureTime = null;

    // Initialise gauge to 0 (closed).
    circuitBreakerGauge.set({ name: this.name }, STATE_VALUES[STATES.CLOSED]);
  }

  // ---------------------------------------------------------------------------
  // Public API
  // ---------------------------------------------------------------------------

  /**
   * Execute `fn` through the circuit breaker.
   *
   * @param {Function} fn  Async (or sync) function to call.
   * @returns {Promise<*>} Resolves with whatever `fn` resolves with.
   * @throws  {Error}      Re-throws errors from `fn`, or throws immediately when
   *                       the circuit is open and the reset window hasn't elapsed.
   */
  async call(fn) {
    if (this.state === STATES.OPEN) {
      const elapsed = Date.now() - this.lastFailureTime;
      if (elapsed > this.resetTimeout) {
        this._transition(STATES.HALF_OPEN);
        logger.info(
          { event: "circuit_breaker_half_open", breaker: this.name, elapsed },
          `Circuit breaker [${this.name}] entering HALF_OPEN after ${elapsed}ms`,
        );
      } else {
        throw new Error(
          `Circuit breaker [${this.name}] is OPEN — requests blocked for ${Math.ceil((this.resetTimeout - elapsed) / 1000)}s`,
        );
      }
    }

    try {
      const result = await fn();
      this._onSuccess();
      return result;
    } catch (err) {
      this._onFailure(err);
      throw err;
    }
  }

  /**
   * Current state string ("closed" | "open" | "half_open").
   * Useful for health checks and tests.
   */
  getState() {
    return this.state;
  }

  /**
   * Current consecutive failure count.
   */
  getFailureCount() {
    return this.failureCount;
  }

  // ---------------------------------------------------------------------------
  // Internal helpers
  // ---------------------------------------------------------------------------

  _onSuccess() {
    if (this.state !== STATES.CLOSED) {
      logger.info(
        { event: "circuit_breaker_closed", breaker: this.name },
        `Circuit breaker [${this.name}] recovered — transitioning to CLOSED`,
      );
    }
    this.failureCount = 0;
    this.lastFailureTime = null;
    this._transition(STATES.CLOSED);
  }

  _onFailure(err) {
    this.failureCount++;
    this.lastFailureTime = Date.now();

    if (this.failureCount >= this.failureThreshold) {
      this._transition(STATES.OPEN);
      logger.error(
        {
          event: "circuit_breaker_open",
          breaker: this.name,
          failures: this.failureCount,
          err: err.message,
        },
        `Circuit breaker [${this.name}] tripped after ${this.failureCount} failures`,
      );
    } else {
      logger.warn(
        {
          event: "circuit_breaker_failure",
          breaker: this.name,
          failures: this.failureCount,
          threshold: this.failureThreshold,
          err: err.message,
        },
        `Circuit breaker [${this.name}] failure ${this.failureCount}/${this.failureThreshold}`,
      );
    }
  }

  _transition(newState) {
    this.state = newState;
    circuitBreakerGauge.set({ name: this.name }, STATE_VALUES[newState]);
  }
}

module.exports = { CircuitBreaker, circuitBreakerGauge, STATES };

/**
 * src/services/circuitBreaker.test.js
 *
 * Unit tests for the CircuitBreaker utility and the withRetry / isRetryable
 * helpers exported from stellar.js.
 *
 * Test scenarios (per issue acceptance criteria):
 *  1. Retry: mock RPC fails 2 times then succeeds — verify retry count
 *  2. Circuit open: mock RPC fails 5 times — verify circuit breaker opens
 *  3. Non-retryable: non-retryable error does NOT trigger retry
 *  4. Half-open → closed: circuit breaker recovers after reset timeout
 *  5. Exponential backoff: delays double on each retry attempt
 *  6. Circuit open rejects immediately without calling fn
 *  7. isRetryable: correctly classifies transient vs non-transient errors
 *  8. Prometheus gauge: reflects circuit state transitions
 *  9. Retry counter: sorobanRpcRetriesTotal increments on each retry
 */
"use strict";

const { CircuitBreaker, STATES } = require("./circuitBreaker");
const { isRetryable, sorobanRpcRetriesTotal } = require("./stellar");

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

/** Build a fresh CircuitBreaker with a very short reset window for tests. */
function makeBreaker(opts = {}) {
  return new CircuitBreaker({
    name: `test_${Date.now()}_${Math.random()}`,
    failureThreshold: 5,
    resetTimeout: 100, // 100 ms reset — fast for tests
    ...opts,
  });
}

/**
 * Build a standalone async `withRetry` function that uses a given CircuitBreaker
 * instance.  This avoids the shared module-level `rpcBreaker` singleton, making
 * tests fully isolated from each other and from real timer delays.
 *
 * @param {CircuitBreaker} breaker
 * @param {number}         [baseDelayMs=0]  Set to 0 in tests to skip real delays.
 */
function makeWithRetry(breaker, baseDelayMs = 0) {
  return async function withRetry(fn, maxRetries = 3) {
    let lastError;
    for (let attempt = 0; attempt <= maxRetries; attempt++) {
      try {
        return await breaker.call(fn);
      } catch (err) {
        lastError = err;
        const circuitOpen = err.message && err.message.includes("Circuit breaker");
        if (circuitOpen) throw lastError;
        if (attempt < maxRetries && isRetryable(err)) {
          const delay = baseDelayMs * Math.pow(2, attempt);
          if (delay > 0) {
            await new Promise((resolve) => setTimeout(resolve, delay));
          }
          sorobanRpcRetriesTotal.inc();
        } else {
          throw lastError;
        }
      }
    }
    throw lastError;
  };
}

// ---------------------------------------------------------------------------
// 1. CircuitBreaker — state machine
// ---------------------------------------------------------------------------

describe("CircuitBreaker — state machine", () => {
  test("starts in CLOSED state", () => {
    const b = makeBreaker();
    expect(b.getState()).toBe(STATES.CLOSED);
    expect(b.getFailureCount()).toBe(0);
  });

  test("passes through successful calls without changing state", async () => {
    const b = makeBreaker();
    const result = await b.call(async () => "hello");
    expect(result).toBe("hello");
    expect(b.getState()).toBe(STATES.CLOSED);
    expect(b.getFailureCount()).toBe(0);
  });

  test("increments failure count on each failed call while CLOSED", async () => {
    const b = makeBreaker({ failureThreshold: 5 });
    for (let i = 1; i <= 4; i++) {
      await expect(
        b.call(async () => {
          throw new Error("boom");
        }),
      ).rejects.toThrow("boom");
      expect(b.getFailureCount()).toBe(i);
      expect(b.getState()).toBe(STATES.CLOSED);
    }
  });

  test("transitions to OPEN after failureThreshold consecutive failures", async () => {
    const b = makeBreaker({ failureThreshold: 5 });
    for (let i = 0; i < 5; i++) {
      await expect(
        b.call(async () => {
          throw new Error("ECONNRESET");
        }),
      ).rejects.toThrow();
    }
    expect(b.getState()).toBe(STATES.OPEN);
  });

  test("rejects immediately when OPEN (does not invoke fn)", async () => {
    const b = makeBreaker({ failureThreshold: 2 });
    // Force open
    for (let i = 0; i < 2; i++) {
      await expect(
        b.call(async () => {
          throw new Error("fail");
        }),
      ).rejects.toThrow();
    }
    expect(b.getState()).toBe(STATES.OPEN);

    const fn = jest.fn();
    await expect(b.call(fn)).rejects.toThrow(/Circuit breaker.*OPEN/i);
    expect(fn).not.toHaveBeenCalled();
  });

  test("transitions OPEN → HALF_OPEN after resetTimeout elapses", async () => {
    const b = makeBreaker({ failureThreshold: 2, resetTimeout: 1 }); // 1 ms
    for (let i = 0; i < 2; i++) {
      await expect(
        b.call(async () => {
          throw new Error("fail");
        }),
      ).rejects.toThrow();
    }
    expect(b.getState()).toBe(STATES.OPEN);

    // Wait long enough for resetTimeout to elapse.
    await new Promise((r) => setTimeout(r, 20));

    // Next call should be attempted (HALF_OPEN), and on success → CLOSED.
    const result = await b.call(async () => "recovered");
    expect(result).toBe("recovered");
    expect(b.getState()).toBe(STATES.CLOSED);
    expect(b.getFailureCount()).toBe(0);
  });

  test("HALF_OPEN → OPEN when the probe call fails", async () => {
    const b = makeBreaker({ failureThreshold: 2, resetTimeout: 1 });
    // Trip the breaker
    for (let i = 0; i < 2; i++) {
      await expect(
        b.call(async () => {
          throw new Error("err");
        }),
      ).rejects.toThrow();
    }
    // Wait for HALF_OPEN window
    await new Promise((r) => setTimeout(r, 20));

    // Probe fails → goes back to OPEN
    await expect(
      b.call(async () => {
        throw new Error("still broken");
      }),
    ).rejects.toThrow("still broken");
    expect(b.getState()).toBe(STATES.OPEN);
  });

  test("success after HALF_OPEN resets failure count to 0", async () => {
    const b = makeBreaker({ failureThreshold: 3, resetTimeout: 1 });
    for (let i = 0; i < 3; i++) {
      await expect(
        b.call(async () => {
          throw new Error("x");
        }),
      ).rejects.toThrow();
    }
    await new Promise((r) => setTimeout(r, 20));

    await b.call(async () => "ok");
    expect(b.getFailureCount()).toBe(0);
    expect(b.getState()).toBe(STATES.CLOSED);
  });
});

// ---------------------------------------------------------------------------
// 2. isRetryable — error classification
// ---------------------------------------------------------------------------

describe("isRetryable", () => {
  test.each([
    ["ECONNRESET", true],
    ["ETIMEDOUT", true],
    ["503 Service Unavailable", true],
    ["502 Bad Gateway", true],
    ["socket hang up", true],
    ["upstream 503 error", true],
    ["got 502", true],
    ["Connection reset by peer (ECONNRESET)", true],
  ])("classifies '%s' as retryable", (msg, expected) => {
    expect(isRetryable(new Error(msg))).toBe(expected);
  });

  test.each([
    ["400 Bad Request — invalid XDR", false],
    ["Transaction failed: txBAD_SEQ", false],
    ["Invalid argument", false],
    ["404 Not Found", false],
    ["Unauthorized", false],
    ["", false],
  ])("classifies '%s' as NOT retryable", (msg, expected) => {
    expect(isRetryable(new Error(msg))).toBe(expected);
  });

  test("handles null/undefined err gracefully", () => {
    expect(isRetryable(null)).toBe(false);
    expect(isRetryable(undefined)).toBe(false);
    expect(isRetryable({})).toBe(false);
  });
});

// ---------------------------------------------------------------------------
// 3. withRetry — retry logic (isolated via makeWithRetry)
// ---------------------------------------------------------------------------

describe("withRetry (retry logic)", () => {
  test("succeeds on first attempt when fn succeeds immediately", async () => {
    const breaker = makeBreaker();
    const withRetryLocal = makeWithRetry(breaker);
    const fn = jest.fn(async () => "result");
    const result = await withRetryLocal(fn, 3);
    expect(result).toBe("result");
    expect(fn).toHaveBeenCalledTimes(1);
  });

  test("retries on transient error and succeeds on 3rd attempt", async () => {
    const breaker = makeBreaker({ failureThreshold: 10 }); // high threshold so breaker stays closed
    const withRetryLocal = makeWithRetry(breaker, 0); // 0 ms delay

    let calls = 0;
    const fn = jest.fn(async () => {
      calls++;
      if (calls <= 2) throw new Error("ECONNRESET");
      return "success";
    });

    const result = await withRetryLocal(fn, 3);
    expect(result).toBe("success");
    expect(fn).toHaveBeenCalledTimes(3);
  });

  test("does NOT retry on non-retryable error", async () => {
    const breaker = makeBreaker({ failureThreshold: 10 });
    const withRetryLocal = makeWithRetry(breaker, 0);

    const fn = jest.fn(async () => {
      throw new Error("400 Bad Request");
    });

    await expect(withRetryLocal(fn, 3)).rejects.toThrow("400 Bad Request");
    // Called only once — no retries.
    expect(fn).toHaveBeenCalledTimes(1);
  });

  test("exhausts retries and re-throws the last error", async () => {
    const breaker = makeBreaker({ failureThreshold: 10 }); // keep breaker closed
    const withRetryLocal = makeWithRetry(breaker, 0);

    const fn = jest.fn(async () => {
      throw new Error("ECONNRESET");
    });

    await expect(withRetryLocal(fn, 2)).rejects.toThrow("ECONNRESET");
    // Initial attempt (0) + 2 retries = 3 calls total.
    expect(fn).toHaveBeenCalledTimes(3);
  });

  test("circuit breaker opens after 5 consecutive failures via withRetry", async () => {
    const breaker = makeBreaker({ failureThreshold: 5, resetTimeout: 60_000 });
    const withRetryLocal = makeWithRetry(breaker, 0);

    const fn = jest.fn(async () => {
      throw new Error("ECONNRESET");
    });

    // Each call to withRetryLocal uses up to maxRetries+1 attempts.
    // We call with maxRetries=0 so each invocation counts as exactly 1 failure.
    for (let i = 0; i < 4; i++) {
      await expect(withRetryLocal(fn, 0)).rejects.toThrow();
    }
    // 5th failure trips the breaker
    await expect(withRetryLocal(fn, 0)).rejects.toThrow();
    expect(breaker.getState()).toBe(STATES.OPEN);
  });

  test("circuit-open error is NOT retried", async () => {
    const breaker = makeBreaker({ failureThreshold: 2, resetTimeout: 60_000 });
    const withRetryLocal = makeWithRetry(breaker, 0);

    // Trip the breaker
    for (let i = 0; i < 2; i++) {
      await expect(
        withRetryLocal(jest.fn(async () => { throw new Error("ECONNRESET"); }), 0),
      ).rejects.toThrow();
    }
    expect(breaker.getState()).toBe(STATES.OPEN);

    // Subsequent call should fail immediately with circuit-open message.
    const fn = jest.fn(async () => "should-not-run");
    await expect(withRetryLocal(fn, 3)).rejects.toThrow(/Circuit breaker/i);
    expect(fn).not.toHaveBeenCalled();
  });
});

