"use strict";

/**
 * src/services/pushQueue.js
 *
 * pg-boss-backed push notification delivery. Route handlers (donations,
 * webhook milestones, project updates) call `enqueuePushNotification()`
 * and return immediately; this worker calls into `pushService` to do
 * the actual Expo send, with pg-boss retrying transient failures.
 */

const PgBoss = require("pg-boss");
const logger = require("../logger");
const pool = require("../db/pool");
const pushService = require("./pushService");

const QUEUE = "push-notifications";
let boss = null;

const HANDLERS = {
  async donation_receipt({ donorAddress, projectId, donationId, amount, currency }) {
    const { rows } = await pool.query(
      "SELECT name FROM projects WHERE id = $1",
      [projectId],
    );
    const projectName = rows[0]?.name || "your project";
    await pushService.sendDonationReceipt(donorAddress, {
      amount,
      currency,
      projectId,
      projectName,
      id: donationId,
    });
  },

  async milestone_reached({ projectId, percentage }) {
    const { rows } = await pool.query(
      "SELECT name FROM projects WHERE id = $1",
      [projectId],
    );
    const projectName = rows[0]?.name || "A project you follow";
    await pushService.sendMilestoneReachedNotifications({
      projectId,
      projectName,
      percentage,
    });
  },

  async project_update({ project, update }) {
    await pushService.sendProjectUpdateNotifications({ project, update });
  },

  async governance_proposal({ proposalId, title, description, endsAt }) {
    await pushService.sendGovernanceProposalNotifications({
      proposalId,
      title,
      description,
      endsAt,
    });
  },

  async recurring_reminder({
    donorAddress,
    projectName,
    amount,
    currency,
    projectId,
    nextPaymentDate,
    recurringId,
  }) {
    await pushService.sendRecurringReminder({
      donorAddress,
      projectName,
      amount,
      currency,
      projectId,
      nextPaymentDate,
      recurringId,
    });
  },
};

/**
 * Start the worker. Idempotent — safe to call more than once.
 */
async function start() {
  if (boss) return;
  const connectionString =
    process.env.DATABASE_URL ||
    "postgres://postgres:postgres@localhost:5432/indigopay";
  boss = new PgBoss(connectionString);
  boss.on("error", (err) =>
    logger.error({ event: "push_queue_error", err: err.message }, "pg-boss error"),
  );
  await boss.start();

  await boss.work(QUEUE, { teamSize: 2, teamConcurrency: 1 }, async (job) => {
    const { type, payload } = job.data || {};
    const handler = HANDLERS[type];
    if (!handler) {
      logger.error(
        { event: "push_job_unknown_type", type, jobId: job.id },
        "Unknown push notification job type",
      );
      return;
    }
    await handler(payload || {});
  });

  logger.info(
    { event: "push_queue_started", queue: QUEUE },
    "push queue worker registered",
  );
}

/**
 * Enqueue a push notification job. `type` must be one of the keys in
 * HANDLERS above.
 */
async function enqueuePushNotification({ type, payload }) {
  if (!HANDLERS[type]) {
    throw new Error(`Unknown push notification type: ${type}`);
  }
  if (!boss) {
    throw new Error("pushQueue not started — call start() first");
  }
  return boss.send(QUEUE, { type, payload }, { retryLimit: 3, retryDelay: 10 });
}

async function stop() {
  if (!boss) return;
  try {
    await boss.stop({ graceful: true, timeout: 15_000 });
  } catch (err) {
    logger.warn(
      { event: "push_queue_stop_error", err: err.message },
      "graceful stop failed",
    );
  }
}

module.exports = { QUEUE, start, stop, enqueuePushNotification };

"use strict";

/**
 * src/services/pushService.js
 *
 * Push notification sending, on top of the Expo Push API. `pushQueue.js`
 * is the pg-boss worker that calls into this module for reliability
 * (retries on transient failures); this module owns the actual send,
 * per-donor preference checks, and delivery tracking in
 * `push_notifications`.
 */

const { Expo } = require("expo-server-sdk");
const { v4: uuid } = require("uuid");
const pool = require("../db/pool");
const logger = require("../logger");

const expo = new Expo(
  process.env.EXPO_ACCESS_TOKEN
    ? { accessToken: process.env.EXPO_ACCESS_TOKEN }
    : undefined,
);

/**
 * Whether a wallet has opted in to push notifications of a given type.
 * No matching row means "opted in" (push defaults to on). A row with
 * type = NULL is a blanket preference for the whole channel; a row with
 * a specific type overrides the blanket one for that type.
 */
/**
 * Check whether the current time falls within the configured DND window.
 * Returns true if notifications should be suppressed right now.
 */
async function isInDndWindow(walletAddress) {
  if (!walletAddress) return false;

  try {
    const { rows } = await pool.query(
      "SELECT notification_dnd FROM profiles WHERE public_key = $1",
      [walletAddress],
    );
    const dnd = rows[0]?.notification_dnd;
    if (!dnd || !dnd.start || !dnd.end) return false;

    const tz = dnd.timezone || "UTC";

    // Parse the current time in the configured timezone using
    // Intl.DateTimeFormat for consistent parsing across Node versions.
    const fmt = new Intl.DateTimeFormat("en-CA", {
      timeZone: tz,
      hour: "2-digit",
      minute: "2-digit",
      hour12: false,
    });
    const timeStr = fmt.format(new Date());
    const [nowH, nowM] = timeStr.split(":").map(Number);
    const nowMinutes = nowH * 60 + nowM;

    const [startH, startM] = dnd.start.split(":").map(Number);
    const [endH, endM] = dnd.end.split(":").map(Number);
    const startMinutes = startH * 60 + startM;
    const endMinutes = endH * 60 + endM;

    if (startMinutes <= endMinutes) {
      // Same-day window (e.g., 08:00–22:00)
      return nowMinutes >= startMinutes && nowMinutes < endMinutes;
    }
    // Overnight window (e.g., 22:00–08:00)
    return nowMinutes >= startMinutes || nowMinutes < endMinutes;
  } catch (err) {
    logger.error(
      {
        event: "dnd_check_failed",
        walletAddress,
        err: err.message,
      },
      "Failed to check DND window; defaulting to not suppressing",
    );
    return false;
  }
}

async function shouldSendPush(walletAddress, type) {
  if (!walletAddress) return false;

  try {
    const { rows } = await pool.query(
      `SELECT enabled FROM notification_preferences
       WHERE wallet_address = $1 AND channel = 'push' AND (type = $2 OR type IS NULL)
       ORDER BY (type IS NULL) ASC
       LIMIT 1`,
      [walletAddress, type || null],
    );
    const optedIn = rows.length === 0 ? true : rows[0].enabled;
    if (!optedIn) return false;

    // Honour DND hours
    if (await isInDndWindow(walletAddress)) return false;

    return true;
  } catch (err) {
    logger.error(
      {
        event: "push_preference_check_failed",
        walletAddress,
        err: err.message,
      },
      "Failed to check notification preferences; defaulting to send",
    );
    return true;
  }
}

async function recordDelivery({
  walletAddress,
  message,
  status,
  ticketId,
  errorMessage,
}) {
  try {
    await pool.query(
      `INSERT INTO push_notifications
         (id, wallet_address, device_token, title, body, data, status, ticket_id, error_message)
       VALUES ($1, $2, $3, $4, $5, $6::jsonb, $7, $8, $9)`,
      [
        uuid(),
        walletAddress || null,
        message.to,
        message.title,
        message.body,
        JSON.stringify(message.data || {}),
        status,
        ticketId || null,
        errorMessage || null,
      ],
    );
  } catch (err) {
    logger.error(
      {
        event: "push_delivery_record_failed",
        walletAddress,
        deviceToken: message.to,
        err: err.message,
      },
      "Failed to record push delivery",
    );
  }
}

/**
 * Send a batch of already-built Expo messages and record the outcome of
 * every ticket (or the chunk-level failure) in `push_notifications`.
 * `walletAddresses[i]` corresponds to `messages[i]` — it may be null for
 * anonymous device follows that have no wallet to check preferences for.
 */
async function dispatch(messages, walletAddresses) {
  if (messages.length === 0) return [];

  const chunks = expo.chunkPushNotifications(messages);
  const tickets = [];
  let cursor = 0;

  for (const chunk of chunks) {
    let ticketChunk;
    try {
      ticketChunk = await expo.sendPushNotificationsAsync(chunk);
    } catch (err) {
      logger.error(
        { event: "push_send_chunk_failed", err: err.message },
        "Failed to send push notification chunk",
      );
      for (let i = 0; i < chunk.length; i++) {
        await recordDelivery({
          walletAddress: walletAddresses[cursor + i],
          message: chunk[i],
          status: "failed",
          errorMessage: err.message,
        });
      }
      cursor += chunk.length;
      continue;
    }

    for (let i = 0; i < ticketChunk.length; i++) {
      const ticket = ticketChunk[i];
      const message = chunk[i];
      const walletAddress = walletAddresses[cursor + i];

      if (ticket.status === "ok") {
        await recordDelivery({
          walletAddress,
          message,
          status: "sent",
          ticketId: ticket.id,
        });
      } else {
        logger.warn(
          {
            event: "push_ticket_error",
            walletAddress,
            deviceToken: message.to,
            error: ticket.details && ticket.details.error,
            message: ticket.message,
          },
          "Expo push ticket reported an error",
        );
        await recordDelivery({
          walletAddress,
          message,
          status: "failed",
          errorMessage: ticket.message,
        });

        // Auto-mark the token inactive when Expo reports it's no longer
        // registered (e.g., user uninstalled the app).
        if (
          ticket.details &&
          ticket.details.error === "DeviceNotRegistered"
        ) {
          try {
            await pool.query(
              "UPDATE device_tokens SET is_active = false, updated_at = NOW() WHERE token = $1",
              [message.to],
            );
            logger.info(
              {
                event: "push_stale_token_marked_inactive",
                deviceToken: message.to,
                walletAddress,
              },
              "Auto-marked stale device token as inactive",
            );
          } catch (err) {
            logger.error(
              {
                event: "push_stale_token_mark_failed",
                deviceToken: message.to,
                err: err.message,
              },
              "Failed to mark stale token inactive",
            );
          }
        }
      }
      tickets.push(ticket);
    }
    cursor += chunk.length;
  }

  return tickets;
}

/**
 * Send a push notification to every device registered for a wallet
 * address, honoring that donor's push preferences for `data.type`.
 */
async function sendPushNotification({ walletAddress, title, body, data = {} }) {
  if (!(await shouldSendPush(walletAddress, data.type))) return null;

  const { rows: tokens } = await pool.query(
    "SELECT token FROM device_tokens WHERE wallet_address = $1 AND is_active = true",
    [walletAddress],
  );

  const messages = [];
  const walletAddresses = [];
  for (const row of tokens) {
    if (!Expo.isExpoPushToken(row.token)) {
      logger.warn(
        { event: "push_invalid_token", walletAddress, token: row.token },
        "Skipping invalid Expo push token",
      );
      continue;
    }
    messages.push({
      to: row.token,
      sound: "default",
      title,
      body,
      data: { ...data, walletAddress },
    });
    walletAddresses.push(walletAddress);
  }

  return dispatch(messages, walletAddresses);
}

async function sendDonationReceipt(donorAddress, donation) {
  return sendPushNotification({
    walletAddress: donorAddress,
    title: "Donation Received! \u{1F331}",
    body: `${donation.amount} ${donation.currency} donated to ${donation.projectName}`,
    data: {
      type: "donation_receipt",
      projectId: donation.projectId,
      donationId: donation.id,
    },
  });
}

/**
 * Notify every wallet-linked follower that a governance proposal is open
 * for voting. Proposals are identified by their on-chain proposalId;
 * the deep link should open the governance voting screen.
 *
 * Batches token lookups into a single JOIN query (same pattern as
 * sendProjectUpdateNotifications) to avoid N+1 DB round-trips.
 */
async function sendGovernanceProposalNotifications({
  proposalId,
  title,
  description,
  endsAt,
}) {
  const { rows: followers } = await pool.query(
    `SELECT DISTINCT dt.token, dt.wallet_address
     FROM device_tokens dt
     WHERE dt.wallet_address IS NOT NULL
       AND dt.is_active = true`,
  );

  const shortBody =
    description && description.length > 120
      ? description.slice(0, 117) + "..."
      : description || "A new proposal is open for voting";

  const data = {
    type: "governance_proposal",
    proposalId,
    ...(endsAt ? { endsAt: new Date(endsAt).toISOString() } : {}),
  };

  const messages = [];
  const walletAddresses = [];
  for (const row of followers) {
    if (!Expo.isExpoPushToken(row.token)) continue;
    if (
      row.wallet_address &&
      !(await shouldSendPush(row.wallet_address, data.type))
    ) {
      continue;
    }
    messages.push({
      to: row.token,
      sound: "default",
      title: `Governance: ${title}`,
      body: shortBody,
      data: row.wallet_address
        ? { ...data, walletAddress: row.wallet_address }
        : data,
    });
    walletAddresses.push(row.wallet_address || null);
  }

  return dispatch(messages, walletAddresses);
}

/**
 * Send a recurring donation reminder to a specific donor 24h before
 * their scheduled payment is due. Called by the recurring donation
 * scheduler (or cron job) for each donor with an upcoming payment.
 */
async function sendRecurringReminder({
  donorAddress,
  projectName,
  amount,
  currency,
  projectId,
  nextPaymentDate,
  recurringId,
}) {
  const payloadData = {
    type: "recurring_reminder",
    projectId,
    recurringId,
    ...(nextPaymentDate
      ? { nextPaymentDate: new Date(nextPaymentDate).toISOString() }
      : {}),
  };

  return sendPushNotification({
    walletAddress: donorAddress,
    title: "Upcoming Donation Reminder \u{1F4AC}",
    body: `Your ${amount} ${currency} recurring donation to ${projectName} will be processed tomorrow`,
    data: payloadData,
  });
}

/**
 * Notify every wallet-linked follower of a project that a funding
 * milestone was reached. Anonymous (wallet-less) follows have no
 * identity to check preferences against, so they're skipped here — see
 * sendProjectUpdateNotifications for the device-token broadcast used by
 * project updates, which does include them.
 */
async function sendMilestoneReachedNotifications({
  projectId,
  projectName,
  percentage,
}) {
  const { rows: followers } = await pool.query(
    `SELECT DISTINCT wallet_address
     FROM project_follows
     WHERE project_id = $1 AND wallet_address IS NOT NULL`,
    [projectId],
  );

  const results = [];
  for (const follower of followers) {
    results.push(
      await sendPushNotification({
        walletAddress: follower.wallet_address,
        title: "Milestone Reached! \u{1F389}",
        body: `${projectName} has reached its ${percentage}% funding milestone!`,
        data: { type: "milestone_reached", projectId },
      }),
    );
  }
  return results;
}

/**
 * Broadcast a project update to every follower's device, wallet-linked
 * or not. Wallet-linked follows are preference-checked like every other
 * push; anonymous device follows have no identity to check preferences
 * against, so they're always sent.
 */
async function sendProjectUpdateNotifications({ project, update }) {
  const { rows: followers } = await pool.query(
    `SELECT dt.token, dt.wallet_address
     FROM project_follows pf
     JOIN device_tokens dt ON pf.device_token_id = dt.id
     WHERE pf.project_id = $1 AND dt.is_active = true`,
    [project.id],
  );

  const title = `Update: ${project.name}`;
  const body = update.title;
  const data = {
    type: "project_update",
    projectId: project.id,
    updateId: update.id,
  };

  const messages = [];
  const walletAddresses = [];
  for (const row of followers) {
    if (!Expo.isExpoPushToken(row.token)) {
      logger.warn(
        {
          event: "push_invalid_token",
          projectId: project.id,
          token: row.token,
        },
        "Skipping invalid Expo push token",
      );
      continue;
    }
    if (
      row.wallet_address &&
      !(await shouldSendPush(row.wallet_address, data.type))
    ) {
      continue;
    }
    messages.push({
      to: row.token,
      sound: "default",
      title,
      body,
      data: row.wallet_address
        ? { ...data, walletAddress: row.wallet_address }
        : data,
    });
    walletAddresses.push(row.wallet_address || null);
  }

  return dispatch(messages, walletAddresses);
}

module.exports = {
  sendPushNotification,
  sendDonationReceipt,
  sendMilestoneReachedNotifications,
  sendProjectUpdateNotifications,
  sendGovernanceProposalNotifications,
  sendRecurringReminder,
  shouldSendPush,
};

/**
 * src/services/storage.js — Document storage abstraction
 *
 * Verification request forms accept supporting documents (PDFs, images,
 * spreadsheets). This service normalises upload handling so the same
 * `uploadFile()` contract works regardless of which backend is configured:
 *
 *   - "local"   (default)  → writes to backend/uploads/<key> and returns a
 *                            static URL served by GET /api/uploads/<key>.
 *                            No external credentials required.
 *   - "s3"     → uploads to a configured S3-compatible bucket using the
 *                AWS SDK; requires AWS_REGION, AWS_ACCESS_KEY_ID,
 *                AWS_SECRET_ACCESS_KEY, S3_BUCKET, optionally S3_PUBLIC_URL.
 *   - "ipfs"   → content-addressed decentralised storage. Two transports
 *                are supported, tried in order:
 *                  1. web3.storage HTTP API (WEB3_STORAGE_API_KEY) — POSTs
 *                     the raw bytes to https://api.web3.storage/upload.
 *                  2. IPFS node HTTP API (IPFS_API_URL) — POSTs a multipart
 *                     file to /api/v0/add (Infura, Pinata cluster, or a
 *                     local IPFS daemon).
 *                Returns the content identifier (CID); the gateway URL is
 *                derived from IPFS_GATEWAY_URL or https://w3s.link/ipfs/<cid>.
 *
 * In addition to the STORAGE_BACKEND dispatch, this module exposes:
 *   - uploadToIPFS(filePath, fileName)   Mirror an already-persisted local
 *     file to IPFS. Used by routes/verification.js to pin supporting
 *     documents at submission time. Never throws: when IPFS is not
 *     configured or the upload fails, it returns { cid: null } so the
 *     local copy remains the source of truth (IPFS_FALLBACK_TO_LOCAL).
 *   - verifyIPFSDocument(cid)   Re-download a document from the IPFS
 *     gateway and compute its SHA-256 so admins can check integrity
 *     against the fingerprint stored at submission time.
 *
 * The active backend is selected by STORAGE_BACKEND env var. If
 * STORAGE_BACKEND is "s3" or "ipfs" but the required credentials or
 * endpoint are missing, we fall back to local storage and log a warning
 * so uploads still succeed (a misconfigured production environment
 * shouldn't silently drop submissions). Set IPFS_FALLBACK_TO_LOCAL=false
 * to make IPFS upload failures hard errors instead.
 *
 * LIMITATIONS:
 *   - These are lightweight, dependency-free adapters. They deliberately
 *     avoid pulling in the full @aws-sdk/client-s3 package to keep the
 *     install footprint small. If you need presigned URLs, multipart
 *     uploads, or KMS encryption, replace the relevant branch with the
 *     official SDK.
 */
"use strict";

const fs = require("fs");
const path = require("path");
const crypto = require("crypto");
const logger = require("../logger");

const STORAGE_BACKEND = process.env.STORAGE_BACKEND || "local";
const UPLOAD_DIR = path.join(__dirname, "..", "..", "uploads");

// Lazy-require AWS SDK so projects that don't use S3 don't need it.
function getAwsS3() {
  // The AWS SDK v3 ships modular packages, so use the bundled v2 client
  // (which is small and works without a build step) when present.
  try {
    // eslint-disable-next-line global-require
    return require("aws-sdk");
  } catch (err) {
    logger.warn(
      { event: "storage_s3_sdk_missing", err: err.message },
      "STORAGE_BACKEND=s3 but aws-sdk is not installed — falling back to local",
    );
    return null;
  }
}

function ensureUploadDir() {
  if (!fs.existsSync(UPLOAD_DIR)) {
    fs.mkdirSync(UPLOAD_DIR, { recursive: true });
  }
}

function buildKey(originalName) {
  const sanitized = String(originalName || "upload")
    .replace(/[^a-zA-Z0-9._-]/g, "_")
    .slice(0, 80);
  const id = crypto.randomBytes(12).toString("hex");
  return `${id}-${sanitized}`;
}

async function uploadLocal(buffer, originalName, contentType) {
  ensureUploadDir();
  const key = buildKey(originalName);
  const fullPath = path.join(UPLOAD_DIR, key);
  await fs.promises.writeFile(fullPath, buffer);
  const url = `/api/uploads/${encodeURIComponent(key)}`;
  return {
    key,
    url,
    size: buffer.length,
    contentType: contentType || "application/octet-stream",
    backend: "local",
  };
}

async function uploadS3(buffer, originalName, contentType) {
  const AWS = getAwsS3();
  if (!AWS) return uploadLocal(buffer, originalName, contentType);

  const required = [
    "AWS_REGION",
    "AWS_ACCESS_KEY_ID",
    "AWS_SECRET_ACCESS_KEY",
    "S3_BUCKET",
  ];
  const missing = required.filter((k) => !process.env[k]);
  if (missing.length > 0) {
    logger.warn(
      { event: "storage_s3_env_missing", missing },
      "STORAGE_BACKEND=s3 but required env vars are missing — falling back to local",
    );
    return uploadLocal(buffer, originalName, contentType);
  }

  const s3 = new AWS.S3({
    region: process.env.AWS_REGION,
    accessKeyId: process.env.AWS_ACCESS_KEY_ID,
    secretAccessKey: process.env.AWS_SECRET_ACCESS_KEY,
  });
  const key = buildKey(originalName);
  await s3
    .putObject({
      Bucket: process.env.S3_BUCKET,
      Key: key,
      Body: buffer,
      ContentType: contentType || "application/octet-stream",
      ACL: "public-read",
    })
    .promise();
  const publicUrl = process.env.S3_PUBLIC_URL
    ? `${process.env.S3_PUBLIC_URL.replace(/\/$/, "")}/${key}`
    : `https://${process.env.S3_BUCKET}.s3.${process.env.AWS_REGION}.amazonaws.com/${key}`;
  return {
    key,
    url: publicUrl,
    size: buffer.length,
    contentType: contentType || "application/octet-stream",
    backend: "s3",
  };
}

async function uploadIpfs(buffer, originalName, contentType) {
  if (!isIpfsConfigured()) {
    logger.warn(
      { event: "storage_ipfs_env_missing" },
      "STORAGE_BACKEND=ipfs but neither WEB3_STORAGE_API_KEY nor IPFS_API_URL is set — falling back to local",
    );
    return uploadLocal(buffer, originalName, contentType);
  }

  try {
    const { cid, size } = await uploadBufferToIpfs(buffer, originalName);
    return {
      key: cid,
      cid,
      url: `${ipfsGatewayBase()}/${cid}`,
      size: size || buffer.length,
      sha256: sha256Hex(buffer),
      contentType: contentType || "application/octet-stream",
      backend: "ipfs",
    };
  } catch (err) {
    if (!ipfsFallbackToLocal()) throw err;
    logger.warn(
      { event: "storage_ipfs_upload_failed", err: err.message },
      "STORAGE_BACKEND=ipfs upload failed — falling back to local",
    );
    return uploadLocal(buffer, originalName, contentType);
  }
}

// ── IPFS helpers ─────────────────────────────────────────────────────────────

// How long we're willing to wait on the IPFS API / gateway before giving up.
function ipfsTimeoutMs() {
  return parseInt(process.env.IPFS_TIMEOUT_MS || "30000", 10);
}

// When true (default), a failed/unconfigured IPFS upload degrades to the
// local copy instead of failing the whole submission.
function ipfsFallbackToLocal() {
  return (
    String(process.env.IPFS_FALLBACK_TO_LOCAL || "true").toLowerCase() !==
    "false"
  );
}

// CIDv0 (Qm..., base58) and CIDv1 (base32/base36) are plain alphanumerics.
// Rejecting anything else keeps user input from injecting path segments
// into the gateway URL we fetch.
const CID_RE = /^[a-zA-Z0-9]{10,128}$/;

function isIpfsConfigured() {
  return Boolean(process.env.WEB3_STORAGE_API_KEY || process.env.IPFS_API_URL);
}

// Gateway base including the /ipfs path prefix. Operators may configure
// either https://w3s.link or https://w3s.link/ipfs; normalize both forms.
function ipfsGatewayBase() {
  const gateway = (process.env.IPFS_GATEWAY_URL || "https://w3s.link").replace(
    /\/$/,
    "",
  );
  return gateway.endsWith("/ipfs") ? gateway : `${gateway}/ipfs`;
}

function sha256Hex(buffer) {
  return crypto.createHash("sha256").update(buffer).digest("hex");
}

/**
 * Upload raw bytes to the web3.storage HTTP API. Kept dependency-free
 * (the official `web3.storage` npm client is deprecated and heavy) —
 * POST /upload with a Bearer token returns `{ cid }`.
 */
async function uploadViaWeb3Storage(buffer, fileName) {
  const base = (
    process.env.WEB3_STORAGE_API_URL || "https://api.web3.storage"
  ).replace(/\/$/, "");
  const res = await fetch(`${base}/upload`, {
    method: "POST",
    headers: {
      Authorization: `Bearer ${process.env.WEB3_STORAGE_API_KEY}`,
      "X-NAME": encodeURIComponent(fileName || "upload"),
    },
    body: buffer,
    signal: AbortSignal.timeout(ipfsTimeoutMs()),
  });
  if (!res.ok) {
    throw new Error(
      `web3.storage upload failed: ${res.status} ${await res.text()}`,
    );
  }
  const json = await res.json();
  if (!json || !json.cid) {
    throw new Error(
      "web3.storage upload succeeded but response did not include a CID",
    );
  }
  return { cid: json.cid, size: buffer.length };
}

/**
 * Upload a file to an IPFS node HTTP API (/api/v0/add). Works with a local
 * daemon, Infura, or a Pinata-compatible cluster endpoint.
 */
async function uploadViaNodeApi(buffer, fileName) {
  const apiUrl = process.env.IPFS_API_URL;

  const FormDataCtor = globalThis.FormData;
  const BlobCtor = globalThis.Blob;
  if (!FormDataCtor || !BlobCtor) {
    throw new Error(
      "IPFS adapter requires Node 18+ global FormData/Blob support",
    );
  }

  const form = new FormDataCtor();
  form.append("file", new BlobCtor([buffer]), fileName || "upload");

  const res = await fetch(
    `${apiUrl.replace(/\/$/, "")}/api/v0/add?wrap-with-directory=false`,
    {
      method: "POST",
      body: form,
      signal: AbortSignal.timeout(ipfsTimeoutMs()),
    },
  );
  if (!res.ok) {
    throw new Error(`IPFS upload failed: ${res.status} ${await res.text()}`);
  }
  const text = await res.text();
  // IPFS CLI HTTP API returns newline-delimited JSON.
  const last = text
    .trim()
    .split(/\r?\n/)
    .map((line) => {
      try {
        return JSON.parse(line);
      } catch {
        return null;
      }
    })
    .filter(Boolean)
    .pop();
  if (!last || !last.Hash) {
    throw new Error("IPFS upload succeeded but response did not include a CID");
  }
  return { cid: last.Hash, size: parseInt(last.Size, 10) || buffer.length };
}

/**
 * Upload a buffer to whichever IPFS transport is configured. web3.storage
 * takes precedence; an IPFS node HTTP API is the fallback. Throws when
 * neither transport is configured.
 */
async function uploadBufferToIpfs(buffer, fileName) {
  if (process.env.WEB3_STORAGE_API_KEY) {
    return uploadViaWeb3Storage(buffer, fileName);
  }
  if (process.env.IPFS_API_URL) {
    return uploadViaNodeApi(buffer, fileName);
  }
  throw new Error(
    "IPFS is not configured: set WEB3_STORAGE_API_KEY or IPFS_API_URL",
  );
}

/**
 * Mirror an already-persisted local file to IPFS. Used by
 * routes/verification.js to pin supporting documents at submission time.
 *
 * Never throws while IPFS_FALLBACK_TO_LOCAL (default true): when IPFS is
 * unconfigured or the upload fails, it resolves `{ cid: null,
 * storage_backend: "local" }` so the caller keeps the local copy as the
 * source of truth. The SHA-256 of the file content is returned so the
 * fingerprint captured at submission time can later be compared against
 * a fresh gateway download (see verifyIPFSDocument).
 *
 * @param {string} filePath - Absolute path of the locally stored file.
 * @param {string} fileName - Display name used for the IPFS pin.
 * @returns {Promise<{cid: string|null, url?: string, sha256?: string, size?: number, storage_backend: string}>}
 */
async function uploadToIPFS(filePath, fileName) {
  if (!isIpfsConfigured()) {
    logger.warn(
      { event: "ipfs_no_key" },
      "WEB3_STORAGE_API_KEY / IPFS_API_URL not set, falling back to local",
    );
    return { cid: null, storage_backend: "local" };
  }

  try {
    const buffer = await fs.promises.readFile(filePath);
    const sha256 = sha256Hex(buffer);
    const { cid, size } = await uploadBufferToIpfs(buffer, fileName);
    logger.info(
      { event: "ipfs_upload_ok", cid, fileName },
      "Supporting document pinned to IPFS",
    );
    return {
      cid,
      url: `${ipfsGatewayBase()}/${cid}`,
      sha256,
      size: size || buffer.length,
      storage_backend: "ipfs",
    };
  } catch (err) {
    if (!ipfsFallbackToLocal()) throw err;
    logger.warn(
      { event: "ipfs_upload_failed", err: err.message, fileName },
      "IPFS upload failed — keeping local copy",
    );
    return { cid: null, storage_backend: "local" };
  }
}

/**
 * Re-download a document from the IPFS gateway and compute its SHA-256 so
 * its integrity can be checked. IPFS URLs are content-addressed, so a
 * successful retrieval already proves the bytes match the CID; comparing
 * the SHA-256 against the fingerprint captured at submission time
 * additionally guards against a misbehaving gateway.
 *
 * @param {string} cid - Content identifier to verify.
 * @param {{fileName?: string, expectedSha256?: string}} [opts]
 * @returns {Promise<{valid: boolean, cid?: string, hash?: string, size?: number, matches?: boolean, error?: string}>}
 */
async function verifyIPFSDocument(cid, opts = {}) {
  if (!CID_RE.test(String(cid || ""))) {
    return { valid: false, error: "Invalid CID" };
  }

  let url = `${ipfsGatewayBase()}/${cid}`;
  if (opts.fileName) url += `/${encodeURIComponent(opts.fileName)}`;

  try {
    const response = await fetch(url, {
      signal: AbortSignal.timeout(ipfsTimeoutMs()),
    });
    if (!response.ok) {
      return {
        valid: false,
        error: `Document not retrievable (HTTP ${response.status})`,
      };
    }
    const buffer = Buffer.from(await response.arrayBuffer());
    const hash = sha256Hex(buffer);
    const result = { valid: true, cid, hash, size: buffer.length };
    if (opts.expectedSha256) {
      result.matches = hash === String(opts.expectedSha256).toLowerCase();
      result.valid = result.matches;
      if (!result.matches) {
        result.error = "Content hash does not match the recorded fingerprint";
      }
    }
    return result;
  } catch (err) {
    return { valid: false, error: `Gateway fetch failed: ${err.message}` };
  }
}

/**
 * Upload a file buffer with metadata, dispatching to the configured backend.
 *
 * @param {Buffer} buffer - File contents.
 * @param {string} originalName - Original filename (sanitised internally).
 * @param {string} contentType - MIME type from the upload.
 * @returns {Promise<{key:string,url:string,size:number,contentType:string,backend:string}>}
 */
async function uploadFile(buffer, originalName, contentType) {
  if (!Buffer.isBuffer(buffer)) {
    throw new Error("uploadFile requires a Buffer");
  }
  const backend = (STORAGE_BACKEND || "local").toLowerCase();
  if (backend === "s3") return uploadS3(buffer, originalName, contentType);
  if (backend === "ipfs") return uploadIpfs(buffer, originalName, contentType);
  return uploadLocal(buffer, originalName, contentType);
}

function backendName() {
  return STORAGE_BACKEND;
}

module.exports = {
  uploadFile,
  backendName,
  uploadToIPFS,
  verifyIPFSDocument,
  isIpfsConfigured,
  UPLOAD_DIR,
};

/**
 * storage.test.js — IPFS adapter unit tests
 *
 * Covers the GF-045 acceptance criteria:
 *   - documents uploaded to IPFS return a CID + gateway URL
 *   - fallback to local storage when no API key / endpoint is configured
 *   - fallback to local storage when the IPFS upload fails
 *   - integrity verification via SHA-256 against a mocked gateway
 *
 * `fetch` (Node 18+ global) is mocked so no network access happens.
 */
"use strict";

const fs = require("fs");
const os = require("os");
const path = require("path");
const crypto = require("crypto");

jest.mock("../logger", () => ({
  info: jest.fn(),
  warn: jest.fn(),
  error: jest.fn(),
}));

const ENV_KEYS = [
  "STORAGE_BACKEND",
  "WEB3_STORAGE_API_KEY",
  "WEB3_STORAGE_API_URL",
  "IPFS_API_URL",
  "IPFS_GATEWAY_URL",
  "IPFS_FALLBACK_TO_LOCAL",
];

const FAKE_CID = "bafybeigdyrzt5sfp7udm7hu76uh7y26nf3efuylqabf3oclgtqy55fbzdi";

describe("services/storage — IPFS", () => {
  let tmpFile;
  const originalEnv = {};
  const originalFetch = global.fetch;

  beforeAll(async () => {
    tmpFile = path.join(os.tmpdir(), `storage-test-${process.pid}.txt`);
    await fs.promises.writeFile(tmpFile, "verification document contents");
  });

  afterAll(async () => {
    await fs.promises.unlink(tmpFile).catch(() => {});
  });

  beforeEach(() => {
    jest.resetModules();
    for (const key of ENV_KEYS) {
      originalEnv[key] = process.env[key];
      delete process.env[key];
    }
    global.fetch = jest.fn();
  });

  afterEach(() => {
    for (const key of ENV_KEYS) {
      if (originalEnv[key] === undefined) delete process.env[key];
      else process.env[key] = originalEnv[key];
    }
    global.fetch = originalFetch;
  });

  function loadStorage() {
    // eslint-disable-next-line global-require
    return require("./storage");
  }

  describe("uploadToIPFS", () => {
    test("returns the CID and gateway URL when web3.storage succeeds", async () => {
      process.env.WEB3_STORAGE_API_KEY = "test-token";
      global.fetch.mockResolvedValue({
        ok: true,
        json: async () => ({ cid: FAKE_CID }),
      });

      const { uploadToIPFS } = loadStorage();
      const result = await uploadToIPFS(tmpFile, "methodology.pdf");

      expect(result.cid).toBe(FAKE_CID);
      expect(result.url).toBe(`https://w3s.link/ipfs/${FAKE_CID}`);
      expect(result.storage_backend).toBe("ipfs");
      // SHA-256 fingerprint of the file is recorded for later verification.
      const expectedHash = crypto
        .createHash("sha256")
        .update("verification document contents")
        .digest("hex");
      expect(result.sha256).toBe(expectedHash);

      // Bearer token flows through to the web3.storage API call.
      const [url, opts] = global.fetch.mock.calls[0];
      expect(url).toBe("https://api.web3.storage/upload");
      expect(opts.headers.Authorization).toBe("Bearer test-token");
    });

    test("respects IPFS_GATEWAY_URL when building the document URL", async () => {
      process.env.WEB3_STORAGE_API_KEY = "test-token";
      process.env.IPFS_GATEWAY_URL = "https://example-gateway.test";
      global.fetch.mockResolvedValue({
        ok: true,
        json: async () => ({ cid: FAKE_CID }),
      });

      const { uploadToIPFS } = loadStorage();
      const result = await uploadToIPFS(tmpFile, "doc.pdf");
      expect(result.url).toBe(`https://example-gateway.test/ipfs/${FAKE_CID}`);
    });

    test("uses the IPFS node HTTP API when only IPFS_API_URL is set", async () => {
      process.env.IPFS_API_URL = "http://127.0.0.1:5001";
      global.fetch.mockResolvedValue({
        ok: true,
        text: async () =>
          JSON.stringify({ Name: "doc.pdf", Hash: FAKE_CID, Size: "31" }),
      });

      const { uploadToIPFS } = loadStorage();
      const result = await uploadToIPFS(tmpFile, "doc.pdf");

      expect(result.cid).toBe(FAKE_CID);
      expect(result.storage_backend).toBe("ipfs");
      const [url] = global.fetch.mock.calls[0];
      expect(url).toBe(
        "http://127.0.0.1:5001/api/v0/add?wrap-with-directory=false",
      );
    });

    test("falls back to local when no API key or endpoint is configured", async () => {
      const { uploadToIPFS } = loadStorage();
      const result = await uploadToIPFS(tmpFile, "doc.pdf");

      expect(result.cid).toBeNull();
      expect(result.storage_backend).toBe("local");
      expect(global.fetch).not.toHaveBeenCalled();
    });

    test("falls back to local when the IPFS upload fails", async () => {
      process.env.WEB3_STORAGE_API_KEY = "test-token";
      global.fetch.mockResolvedValue({
        ok: false,
        status: 502,
        text: async () => "bad gateway",
      });

      const { uploadToIPFS } = loadStorage();
      const result = await uploadToIPFS(tmpFile, "doc.pdf");

      expect(result.cid).toBeNull();
      expect(result.storage_backend).toBe("local");
    });

    test("propagates upload errors when IPFS_FALLBACK_TO_LOCAL=false", async () => {
      process.env.WEB3_STORAGE_API_KEY = "test-token";
      process.env.IPFS_FALLBACK_TO_LOCAL = "false";
      global.fetch.mockResolvedValue({
        ok: false,
        status: 500,
        text: async () => "boom",
      });

      const { uploadToIPFS } = loadStorage();
      await expect(uploadToIPFS(tmpFile, "doc.pdf")).rejects.toThrow(
        /web3.storage upload failed/,
      );
    });
  });

  describe("verifyIPFSDocument", () => {
    const CONTENT = Buffer.from("verification document contents");
    const CONTENT_SHA256 = crypto
      .createHash("sha256")
      .update(CONTENT)
      .digest("hex");

    test("retrieves the document and returns its SHA-256", async () => {
      global.fetch.mockResolvedValue({
        ok: true,
        arrayBuffer: async () =>
          CONTENT.buffer.slice(
            CONTENT.byteOffset,
            CONTENT.byteOffset + CONTENT.byteLength,
          ),
      });

      const { verifyIPFSDocument } = loadStorage();
      const result = await verifyIPFSDocument(FAKE_CID);

      expect(result.valid).toBe(true);
      expect(result.hash).toBe(CONTENT_SHA256);
      expect(result.size).toBe(CONTENT.length);
      const [url] = global.fetch.mock.calls[0];
      expect(url).toBe(`https://w3s.link/ipfs/${FAKE_CID}`);
    });

    test("reports matches=true when the expected SHA-256 matches", async () => {
      global.fetch.mockResolvedValue({
        ok: true,
        arrayBuffer: async () =>
          CONTENT.buffer.slice(
            CONTENT.byteOffset,
            CONTENT.byteOffset + CONTENT.byteLength,
          ),
      });

      const { verifyIPFSDocument } = loadStorage();
      const result = await verifyIPFSDocument(FAKE_CID, {
        expectedSha256: CONTENT_SHA256,
      });
      expect(result.valid).toBe(true);
      expect(result.matches).toBe(true);
    });

    test("flags tampering when the retrieved hash does not match", async () => {
      global.fetch.mockResolvedValue({
        ok: true,
        arrayBuffer: async () =>
          CONTENT.buffer.slice(
            CONTENT.byteOffset,
            CONTENT.byteOffset + CONTENT.byteLength,
          ),
      });

      const { verifyIPFSDocument } = loadStorage();
      const result = await verifyIPFSDocument(FAKE_CID, {
        expectedSha256: "a".repeat(64),
      });
      expect(result.valid).toBe(false);
      expect(result.matches).toBe(false);
      expect(result.error).toMatch(/does not match/);
    });

    test("returns valid=false when the gateway responds with an error", async () => {
      global.fetch.mockResolvedValue({ ok: false, status: 404 });

      const { verifyIPFSDocument } = loadStorage();
      const result = await verifyIPFSDocument(FAKE_CID);
      expect(result.valid).toBe(false);
      expect(result.error).toMatch(/not retrievable/);
    });

    test("returns valid=false when the gateway is unreachable", async () => {
      global.fetch.mockRejectedValue(new Error("ECONNREFUSED"));

      const { verifyIPFSDocument } = loadStorage();
      const result = await verifyIPFSDocument(FAKE_CID);
      expect(result.valid).toBe(false);
      expect(result.error).toMatch(/Gateway fetch failed/);
    });

    test("rejects malformed CIDs without touching the network", async () => {
      const { verifyIPFSDocument } = loadStorage();
      const result = await verifyIPFSDocument("../../../etc/passwd");
      expect(result.valid).toBe(false);
      expect(result.error).toBe("Invalid CID");
      expect(global.fetch).not.toHaveBeenCalled();
    });
  });

  describe("uploadFile (STORAGE_BACKEND=ipfs)", () => {
    test("returns cid + ipfs backend when configured", async () => {
      process.env.STORAGE_BACKEND = "ipfs";
      process.env.WEB3_STORAGE_API_KEY = "test-token";
      global.fetch.mockResolvedValue({
        ok: true,
        json: async () => ({ cid: FAKE_CID }),
      });

      const { uploadFile } = loadStorage();
      const result = await uploadFile(
        Buffer.from("hello"),
        "doc.pdf",
        "application/pdf",
      );
      expect(result.backend).toBe("ipfs");
      expect(result.cid).toBe(FAKE_CID);
      expect(result.url).toBe(`https://w3s.link/ipfs/${FAKE_CID}`);
    });

    test("falls back to local when IPFS is unconfigured", async () => {
      process.env.STORAGE_BACKEND = "ipfs";

      const { uploadFile } = loadStorage();
      const result = await uploadFile(
        Buffer.from("hello"),
        "doc.pdf",
        "application/pdf",
      );
      expect(result.backend).toBe("local");
      expect(result.url).toMatch(/^\/api\/uploads\//);
      // Clean up the file the local fallback wrote.
      const { UPLOAD_DIR } = loadStorage();
      await fs.promises
        .unlink(path.join(UPLOAD_DIR, result.key))
        .catch(() => {});
    });

    test("falls back to local when a configured IPFS upload fails", async () => {
      process.env.STORAGE_BACKEND = "ipfs";
      process.env.WEB3_STORAGE_API_KEY = "test-token";
      global.fetch.mockResolvedValue({
        ok: false,
        status: 503,
        text: async () => "unavailable",
      });

      const { uploadFile, UPLOAD_DIR } = loadStorage();
      const result = await uploadFile(
        Buffer.from("hello"),
        "doc.pdf",
        "application/pdf",
      );

      expect(result.backend).toBe("local");
      expect(result.url).toMatch(/^\/api\/uploads\//);
      await fs.promises
        .unlink(path.join(UPLOAD_DIR, result.key))
        .catch(() => {});
    });
  });
});

/**
 * services/turrets.js
 * Stellar Turrets txFunction server for automatic donation matching
 *
 * This service implements a Turrets-compatible txFunction that:
 * 1. Listens for payments to project wallets
 * 2. Checks for active matching offers
 * 3. Submits pre-signed matching transactions from the matcher account
 */

const {
  Server,
  TransactionBuilder,
  Networks,
  Operation,
  Asset,
} = require("@stellar/stellar-sdk");
const pool = require("../db/pool");

// Network configuration
const NETWORK = process.env.STELLAR_NETWORK || "testnet";
const NETWORK_PASSPHRASE =
  NETWORK === "mainnet" ? Networks.PUBLIC : Networks.TESTNET;
const HORIZON_URL =
  process.env.HORIZON_URL || "https://horizon-testnet.stellar.org";
let server;
function getServer() {
  if (!server) {
    server = new Server(HORIZON_URL);
  }
  return server;
}

/**
 * Turrets txFunction entry point for matching donations
 * This function is called by the Turret when a payment is detected
 */
async function matchDonationTxFunction(payment) {
  try {
    const { transaction_hash, from, to, amount, asset_code, asset_type } =
      payment;

    // Only match XLM donations
    if (asset_type !== "native" && asset_code !== "XLM") {
      console.log(`Skipping non-XLM donation: ${asset_code || asset_type}`);
      return { matched: false, reason: "Not an XLM donation" };
    }

    // Find the project by wallet address
    const projectResult = await pool.query(
      "SELECT id, name FROM projects WHERE wallet_address = $1",
      [to],
    );

    if (!projectResult.rows[0]) {
      console.log(`Project not found for wallet: ${to}`);
      return { matched: false, reason: "Project not found" };
    }

    const project = projectResult.rows[0];
    const donationAmount = parseFloat(amount);

    // Check for active matching offers
    const matchesResult = await pool.query(
      `SELECT id, matcher_address, cap_xlm, matched_xlm, multiplier
       FROM donation_matches
       WHERE project_id = $1 AND expires_at > NOW()
       ORDER BY created_at ASC`,
      [project.id],
    );

    if (matchesResult.rows.length === 0) {
      console.log(`No active matching offers for project: ${project.id}`);
      return { matched: false, reason: "No active matching offers" };
    }

    // Process matching offers
    let totalMatched = 0;
    const matchResults = [];

    for (const match of matchesResult.rows) {
      const matchedXlm = parseFloat(match.matched_xlm || "0");
      const capXlm = parseFloat(match.cap_xlm);
      const remaining = capXlm - matchedXlm;

      if (remaining <= 0) continue;

      const matchAmount = Math.min(
        donationAmount * match.multiplier,
        remaining,
      );

      if (matchAmount <= 0) continue;

      // Build and submit the matching payment transaction
      const matchResult = await submitMatchingPayment({
        matcherAddress: match.matcher_address,
        projectWallet: to,
        amount: matchAmount,
        originalTxHash: transaction_hash,
        matchId: match.id,
      });

      if (matchResult.success) {
        // Update the matched amount in the database
        await pool.query(
          `UPDATE donation_matches 
           SET matched_xlm = matched_xlm + $1 
           WHERE id = $2`,
          [matchAmount, match.id],
        );

        // Record the matched donation
        await pool.query(
          `INSERT INTO donations (
            id, project_id, donor_address, amount_xlm, amount, currency, 
            message, transaction_hash, created_at
          )
          VALUES ($1, $2, $3, $4, $5, $6, $7, $8, NOW())`,
          [
            require("uuid").v4(),
            project.id,
            match.matcher_address,
            matchAmount,
            matchAmount,
            "XLM",
            `Matching donation for ${from}`,
            matchResult.txHash,
          ],
        );

        totalMatched += matchAmount;
        matchResults.push({
          matcherAddress: match.matcher_address,
          amount: matchAmount,
          txHash: matchResult.txHash,
        });
      }
    }

    return {
      matched: totalMatched > 0,
      totalMatched,
      matches: matchResults,
      projectId: project.id,
      projectName: project.name,
    };
  } catch (error) {
    console.error("Error in matchDonationTxFunction:", error);
    return { matched: false, error: error.message };
  }
}

/**
 * Turrets txFunction entry point for matching donations.
 *
 * @param {object} payment - Payment operation object from Horizon/Turret.
 * @returns {Promise<object>} Result describing whether matching occurred and details.
 * @throws {Error} If internal processing fails unexpectedly.
 */
// exported as `matchDonationTxFunction`

/**
 * Submit a matching payment transaction
 * This uses pre-signed transactions from the matcher's account
 */
async function submitMatchingPayment({
  matcherAddress,
  projectWallet,
  amount,
  originalTxHash,
  matchId,
}) {
  try {
    // Load the matcher account
    const matcherAccount = await getServer().loadAccount(matcherAddress);

    // Build the payment transaction
    const transaction = new TransactionBuilder(matcherAccount, {
      fee: "100",
      networkPassphrase: NETWORK_PASSPHRASE,
    })
      .addOperation(
        Operation.payment({
          destination: projectWallet,
          asset: Asset.native(),
          amount: amount.toFixed(7),
        }),
      )
      .addMemo(
        Operation.memo({
          type: "text",
          value: `Match:${originalTxHash.slice(0, 20)}`,
        }),
      )
      .setTimeout(60)
      .build();

    // In a real implementation, this would use pre-signed transactions
    // For now, we'll need the matcher's secret key to sign
    // This should be stored securely (e.g., in environment variables or a secret manager)
    const matcherSecret = process.env.MATCHER_SECRET_KEY;

    if (!matcherSecret) {
      console.warn(
        "MATCHER_SECRET_KEY not configured. Cannot submit matching payment.",
      );
      return { success: false, reason: "Matcher secret not configured" };
    }

    // Sign the transaction
    transaction.sign(
      require("@stellar/stellar-sdk").Keypair.fromSecret(matcherSecret),
    );

    // Submit to Horizon
    const result = await getServer().submitTransaction(transaction);

    console.log(`Matching payment submitted: ${result.hash}`);

    return {
      success: true,
      txHash: result.hash,
    };
  } catch (error) {
    console.error("Error submitting matching payment:", error);
    return { success: false, error: error.message };
  }
}

/**
 * Submit a matching payment transaction for a matcher account.
 *
 * @param {{matcherAddress:string,projectWallet:string,amount:number,originalTxHash:string,matchId:string,projectId:string}} opts
 * @returns {Promise<{success:boolean,txHash?:string,reason?:string,error?:string}>}
 */
// exported as `submitMatchingPayment`

/**
 * Generate pre-signed transactions for a matcher up to a cap
 * This allows the Turret to submit transactions without needing the secret key at runtime
 */
async function generatePreSignedTransactions({
  matcherAddress,
  matcherSecret,
  projectWallet,
  capXlm,
  multiplier,
}) {
  const transactions = [];
  const matcherKeypair = require("@stellar/stellar-sdk").Keypair.fromSecret(
    matcherSecret,
  );

  // Generate transactions for different donation amounts
  const donationAmounts = [10, 25, 50, 100, 250];

  for (const donationAmount of donationAmounts) {
    const matchAmount = Math.min(donationAmount * multiplier, capXlm);

    if (matchAmount <= 0) continue;

    try {
      const account = await getServer().loadAccount(matcherAddress);

      const tx = new TransactionBuilder(account, {
        fee: "100",
        networkPassphrase: NETWORK_PASSPHRASE,
      })
        .addOperation(
          Operation.payment({
            destination: projectWallet,
            asset: Asset.native(),
            amount: matchAmount.toFixed(7),
          }),
        )
        .setTimeout(60)
        .build();

      tx.sign(matcherKeypair);

      transactions.push({
        donationAmount,
        matchAmount,
        xdr: tx.toXDR(),
      });
    } catch (error) {
      console.error(
        `Error generating transaction for ${donationAmount} XLM:`,
        error,
      );
    }
  }

  return transactions;
}

/**
 * Generate a set of pre-signed matching transactions for a matcher account.
 *
 * @param {{matcherAddress:string,matcherSecret:string,projectWallet:string,capXlm:number,multiplier:number}} opts
 * @returns {Promise<Array<{donationAmount:number,matchAmount:number,xdr:string}>>}
 */
// exported as `generatePreSignedTransactions`

/**
 * Start the Turrets server
 * This creates an HTTP server that Turrets can call
 */
function startTurretsServer(port = 3001) {
  const express = require("express");
  const { adminKeyRequired } = require("../middleware/auth");
  const app = express();

  app.use(express.json());
  app.use(require("cors")());

  // Health check endpoint
  app.get("/health", (req, res) => {
    res.json({ status: "ok", service: "turrets-matching" });
  });

  // txFunction endpoint for matching donations
  app.post("/txfunction/matchDonation", async (req, res) => {
    try {
      const result = await matchDonationTxFunction(req.body);
      res.json(result);
    } catch (error) {
      console.error("Error in txFunction:", error);
      res.status(500).json({ error: error.message });
    }
  });

  // Endpoint to generate pre-signed transactions
  app.post("/admin/presign", adminKeyRequired, async (req, res) => {
    try {
      const {
        matcherAddress,
        matcherSecret,
        projectWallet,
        capXlm,
        multiplier,
        projectId,
      } = req.body;

      if (!matcherAddress || !matcherSecret || !projectWallet) {
        return res.status(400).json({ error: "Missing required parameters" });
      }

      const transactions = await generatePreSignedTransactions({
        matcherAddress,
        matcherSecret,
        projectWallet,
        capXlm: parseFloat(capXlm),
        multiplier: parseFloat(multiplier),
      });

      res.json({ success: true, transactions });
    } catch (error) {
      console.error("Error generating pre-signed transactions:", error);
      res.status(500).json({ error: error.message });
    }
  });

  app.listen(port, () => {
    console.log(`Turrets server listening on port ${port}`);
  });

  return app;
}

/**
 * Start a lightweight Turrets-compatible HTTP server exposing matching endpoints.
 *
 * @param {number} [port=3001] - TCP port to listen on.
 * @returns {object} Express app instance.
 */
// exported as `startTurretsServer`

module.exports = {
  matchDonationTxFunction,
  submitMatchingPayment,
  generatePreSignedTransactions,
  startTurretsServer,
};

"use strict";

/**
 * src/services/webhookQueue.js
 *
 * pg-boss-backed webhook delivery. The route handler that observes a
 * milestone reaches `enqueueWebhookDelivery()` and returns immediately;
 * this worker does the signed POST, retries with exponential backoff,
 * and finally writes terminal failures to `webhook_dlq`.
 *
 * Wire format (kept stable for partners):
 *   - X-Webhook-Id:        event_id (sha256 of canonical milestone fields)
 *   - X-Webhook-Timestamp: unix seconds at sign time
 *   - X-Webhook-Signature: t=<ts>,v1=<hex hmac-sha256(secret, `${ts}.body`)>
 *   - X-Webhook-Event-Type: e.g. "milestone.reached"
 *   - X-Webhook-Attempt:   1-based attempt number
 *   - X-Webhook-Delivery-Id: uuid of the webhook_deliveries row
 *
 * Retry policy: 30s, 2m, 10m, 30m, 2h, 6h (6 attempts) before DLQ.
 */

const crypto = require("crypto");
const https = require("https");
const http = require("http");
const { URL } = require("url");
const PgBoss = require("pg-boss");

const pool = require("../db/pool");
const logger = require("../logger");
const { metrics } = require("./metrics");
const {
  computeEventId,
  sign,
  DEFAULT_REPLAY_WINDOW_SECONDS,
} = require("../lib/webhookSign");

const QUEUE = "webhook-deliveries";
const RETRY_DELAYS_SECONDS = [30, 120, 600, 1800, 7200, 21600]; // 6 attempts
const TIMEOUT_MS = 10_000;
const USER_AGENT = "Stellar-IndigoPay-Webhook/1.0";

let boss = null;

/**
 * Start the worker. Idempotent — safe to call more than once.
 * Must be called AFTER migrations run and BEFORE the HTTP server accepts traffic.
 */
async function start() {
  if (boss) return;
  const connectionString =
    process.env.DATABASE_URL ||
    "postgres://postgres:postgres@localhost:5432/indigopay";
  boss = new PgBoss(connectionString);
  boss.on("error", (err) =>
    logger.error(
      { event: "webhook_queue_error", err: err.message },
      "pg-boss error",
    ),
  );
  await boss.start();

  await boss.work(
    QUEUE,
    {
      teamSize: 2,
      teamConcurrency: 1,
      retryLimit: RETRY_DELAYS_SECONDS.length,
    },
    async (job) => {
      const { deliveryId } = job.data || {};
      if (!deliveryId) {
        // Defensive: malformed job. Don't retry.
        logger.error(
          { event: "webhook_delivery_malformed", jobId: job.id },
          "missing deliveryId",
        );
        return;
      }
      await processDelivery(deliveryId);
    },
  );

  logger.info(
    { event: "webhook_queue_started", queue: QUEUE },
    "webhook queue worker registered",
  );
}

/**
 * Enqueue a webhook delivery. Returns the event_id (sha256) which is
 * also the unique key in webhook_deliveries — repeat enqueues with the
 * same canonical fields will collide on the UNIQUE constraint and the
 * caller can treat that as "already scheduled".
 */
async function enqueueWebhookDelivery({
  projectId,
  eventType,
  payload,
  secret,
}) {
  const eventId = computeEventId({
    projectId,
    milestoneId: payload.milestoneId ?? null,
    percentage: payload.percentage ?? 0,
    raisedXlm: payload.totalRaisedXLM ?? payload.raisedXlm ?? "0",
  });

  const tentativeId = crypto.randomUUID();
  let deliveryId;
  let wasInserted = true;
  try {
    // Use ON CONFLICT ... DO UPDATE ... RETURNING to atomically claim a row id
    // and discover whether we created it or matched an existing one. The
    // xmax = 0 trick distinguishes a freshly-inserted tuple from one that
    // was already present (xmax != 0 in that case).
    const result = await pool.query(
      `INSERT INTO webhook_deliveries
         (id, project_id, event_id, event_type, payload, status, next_attempt_at)
       VALUES ($1, $2, $3, $4, $5::jsonb, 'pending', NOW())
       ON CONFLICT (event_id) DO UPDATE
         SET updated_at = NOW()
       RETURNING id, (xmax = 0) AS inserted`,
      [tentativeId, projectId, eventId, eventType, JSON.stringify(payload)],
    );
    deliveryId = result.rows[0].id;
    wasInserted = result.rows[0].inserted;
  } catch (err) {
    logger.error(
      {
        event: "webhook_enqueue_db_error",
        err: err.message,
        projectId,
        eventId,
      },
      "failed to record delivery row",
    );
    throw err;
  }

  if (!boss) {
    // During tests / one-off scripts: skip the queue and process inline.
    // Retries are unavailable in this mode; the row sits at status=pending
    // and a future enqueueWebhookDelivery for the same event_id will pick
    // it up via the ON CONFLICT branch above.
    await processDelivery(deliveryId, {
      eventId,
      projectId,
      eventType,
      payload,
      secret,
    });
    return eventId;
  }

  // Schedule a single-attempt pg-boss job. We control retries ourselves
  // (see processDelivery) so the worker doesn't auto-retry on throw —
  // instead, on failure we reschedule a new job with `startAfter` set to
  // the appropriate backoff.
  await boss.send(QUEUE, { deliveryId, secret }, { retryLimit: 0 });

  if (!wasInserted) {
    logger.info(
      { event: "webhook_dedupe_hit", eventId, deliveryId },
      "duplicate webhook enqueue collapsed to existing delivery",
    );
  }
  return eventId;
}

/**
 * Load the delivery row, sign + POST it, record outcome.
 * Exposed for the in-memory path used when pg-boss isn't started.
 */
async function processDelivery(deliveryId, inMemoryOverrides) {
  const { rows } = await pool.query(
    `SELECT d.id, d.project_id, d.event_id, d.event_type, d.payload, d.attempts,
            p.webhook_url, p.webhook_secret
       FROM webhook_deliveries d
       JOIN projects p ON p.id = d.project_id
      WHERE d.id = $1`,
    [deliveryId],
  );
  const row = rows[0];
  if (!row) {
    logger.warn(
      { event: "webhook_delivery_missing", deliveryId },
      "delivery row vanished",
    );
    return;
  }
  if (row.status === "delivered") {
    return; // idempotent skip
  }

  const secret =
    (inMemoryOverrides && inMemoryOverrides.secret) || row.webhook_secret;
  const url = row.webhook_url;
  if (!url || !secret) {
    await markTerminal(
      deliveryId,
      "failed",
      "missing webhook_url or webhook_secret",
    );
    metrics.webhookDeliveriesTotal.inc({ outcome: "skipped" });
    return;
  }

  const body = JSON.stringify({
    id: row.event_id,
    type: row.event_type,
    ...row.payload,
  });
  const timestamp = Math.floor(Date.now() / 1000);
  const signature = sign(body, secret, timestamp);

  metrics.webhookAttemptsTotal.inc({ event_type: row.event_type });
  const result = await postSigned(url, body, {
    eventId: row.event_id,
    eventType: row.event_type,
    deliveryId,
    timestamp,
    signature,
    attempt: row.attempts + 1,
  });

  if (result.ok) {
    await pool.query(
      `UPDATE webhook_deliveries
          SET status='delivered',
              attempts = attempts + 1,
              last_attempt_at = NOW(),
              last_error = NULL,
              next_attempt_at = NULL,
              updated_at = NOW()
        WHERE id = $1`,
      [deliveryId],
    );
    metrics.webhookDeliveriesTotal.inc({ outcome: "delivered" });
    logger.info(
      {
        event: "webhook_delivered",
        deliveryId,
        projectId: row.project_id,
        status: result.statusCode,
      },
      "Webhook delivered",
    );
    return;
  }

  const nextAttempt = row.attempts + 1;
  const willRetry = nextAttempt < RETRY_DELAYS_SECONDS.length;
  const nextDelay = willRetry ? RETRY_DELAYS_SECONDS[nextAttempt] : 0;
  const nextStatus = willRetry ? "pending" : "dlq";

  await pool.query(
    `UPDATE webhook_deliveries
        SET attempts = attempts + 1,
            last_attempt_at = NOW(),
            last_error = $2,
            status = $3,
            next_attempt_at = $4,
            updated_at = NOW()
      WHERE id = $1`,
    [
      deliveryId,
      result.error,
      nextStatus,
      willRetry ? new Date(Date.now() + nextDelay * 1000) : null,
    ],
  );

  if (!willRetry) {
    await pool.query(
      `INSERT INTO webhook_dlq (id, delivery_id, project_id, event_id, payload, failure_reason, attempts)
       VALUES ($1, $2, $3, $4, $5::jsonb, $6, $7)`,
      [
        crypto.randomUUID(),
        deliveryId,
        row.project_id,
        row.event_id,
        JSON.stringify(row.payload),
        result.error,
        nextAttempt,
      ],
    );
    metrics.webhookDeliveriesTotal.inc({ outcome: "dlq" });
  } else {
    metrics.webhookDeliveriesTotal.inc({ outcome: "retry" });
    // Reschedule the next attempt with `startAfter` so the delay is
    // honored even though pg-boss itself isn't doing retries. Without
    // this, the delivery row would sit at status='pending' forever and
    // the advertised 6-attempt backoff would never actually fire.
    if (boss) {
      try {
        await boss.send(
          QUEUE,
          { deliveryId, secret: inMemoryOverrides ? secret : undefined },
          {
            retryLimit: 0,
            startAfter: new Date(Date.now() + nextDelay * 1000),
          },
        );
      } catch (err) {
        logger.error(
          { event: "webhook_reschedule_error", deliveryId, err: err.message },
          "failed to reschedule retry — row left in pending state",
        );
      }
    } else {
      logger.warn(
        { event: "webhook_retry_unavailable", deliveryId },
        "pg-boss not started; cannot reschedule retry, row left in pending state",
      );
    }
  }
  logger.warn(
    {
      event: "webhook_delivery_failed",
      deliveryId,
      attempt: nextAttempt,
      willRetry,
      err: result.error,
      statusCode: result.statusCode,
    },
    "Webhook delivery failed",
  );
}

/**
 * Replay a dead-lettered delivery: resets its attempt counter so it gets
 * the full retry budget again, then immediately attempts redelivery
 * in-process (the admin-facing replay endpoints want a synchronous
 * result rather than waiting on the queue worker).
 *
 * Only rows currently in the 'dlq' state are eligible — replaying a
 * delivery that's still pending/delivered/failed would race the
 * regular retry path.
 *
 * @param {string} deliveryId - webhook_deliveries.id to replay.
 * @returns {Promise<boolean>} true if a dlq row was found and replayed, false otherwise.
 */
async function replayDelivery(deliveryId) {
  const { rows } = await pool.query(
    `UPDATE webhook_deliveries
        SET status = 'pending',
            attempts = 0,
            last_error = NULL,
            next_attempt_at = NOW(),
            updated_at = NOW()
      WHERE id = $1 AND status = 'dlq'
      RETURNING id`,
    [deliveryId],
  );
  if (!rows[0]) return false;

  await processDelivery(deliveryId);
  return true;
}

async function markTerminal(deliveryId, status, error) {
  await pool.query(
    `UPDATE webhook_deliveries
        SET status = $2, last_error = $3, last_attempt_at = NOW(), updated_at = NOW()
      WHERE id = $1`,
    [deliveryId, status, error],
  );
}

function postSigned(urlString, body, headers) {
  return new Promise((resolve) => {
    let urlObj;
    try {
      urlObj = new URL(urlString);
    } catch (err) {
      return resolve({ ok: false, error: `invalid URL: ${err.message}` });
    }
    const lib = urlObj.protocol === "https:" ? https : http;
    const req = lib.request(
      {
        hostname: urlObj.hostname,
        port: urlObj.port || (urlObj.protocol === "https:" ? 443 : 80),
        path: urlObj.pathname + urlObj.search,
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          "Content-Length": Buffer.byteLength(body),
          "User-Agent": USER_AGENT,
          "X-Webhook-Id": headers.eventId,
          "X-Webhook-Event-Type": headers.eventType,
          "X-Webhook-Delivery-Id": headers.deliveryId,
          "X-Webhook-Timestamp": String(headers.timestamp),
          "X-Webhook-Signature": headers.signature,
          "X-Webhook-Attempt": String(headers.attempt),
        },
        timeout: TIMEOUT_MS,
      },
      (res) => {
        res.on("data", () => {});
        res.on("end", () => {
          if (res.statusCode >= 200 && res.statusCode < 300) {
            return resolve({ ok: true, statusCode: res.statusCode });
          }
          resolve({
            ok: false,
            statusCode: res.statusCode,
            error: `non-2xx: ${res.statusCode}`,
          });
        });
      },
    );
    req.on("error", (err) => resolve({ ok: false, error: err.message }));
    req.on("timeout", () => {
      req.destroy();
      resolve({ ok: false, error: "timeout" });
    });
    req.write(body);
    req.end();
  });
}

async function stop() {
  if (!boss) return;
  try {
    await boss.stop({ graceful: true, timeout: 15_000 });
  } catch (err) {
    logger.warn(
      { event: "webhook_queue_stop_error", err: err.message },
      "graceful stop failed",
    );
  }
}

module.exports = {
  QUEUE,
  RETRY_DELAYS_SECONDS,
  start,
  stop,
  enqueueWebhookDelivery,
  processDelivery,
  replayDelivery,
  // Re-export for tests / advanced callers
  sign,
  computeEventId,
  DEFAULT_REPLAY_WINDOW_SECONDS,
};
